mapper.select:
SELECT nu.notification_user_id AS id, nu.user_id, nu.viewed, n.sender_id, n.message, n.created_at,
u.name, w.workshop_id AS workshopId, w.name AS workshopName FROM notification_user nu LEFT JOIN notification n ON nu.notification_id = n.notification_id LEFT JOIN user u ON n.sender_id = u.user_id LEFT JOIN workshop w ON n.workshop_id = w.workshop_id WHERE nu.user_id = #{userId}
AND nu.viewed = FALSE
AND nu.viewed = TRUE
ORDER BY n.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*) FROM notification_user nu LEFT JOIN notification n ON nu.notification_id = n.notification_id WHERE nu.user_id = #{userId}
AND nu.viewed = FALSE
AND nu.viewed = TRUE

